Modified parallel-regret insertion with dynamic penalty adjustment: evaluate all feasible insertions across existing routes and potential new vehicles using a two-stage cost calculation that balances immediate marginal cost increase with future opportunity cost via a regret-based penalty factor.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	for idx := 0; idx < nOrders; idx++ {
		shipID := total_ship + idx
		type candidate struct {
			assignIdx int
			marginal  float64
			routePos  int
		}
		var candidates []candidate
		basePenalty := 0.0
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			if dispatch.Assigns[ai].Cost > basePenalty {
				basePenalty = dispatch.Assigns[ai].Cost
			}
		}
		penaltyFactor := 1.5
		regretThreshold := basePenalty / float64(nOrders+1)
		for ai := 0; ai <= dispatch.AssignsLen; ai++ {
			if ai == MAXASSIGNS {
				break
			}
			a := &dispatch.Assigns[ai]
			if ai < dispatch.AssignsLen {
				if a.GenRoute(); a.Cost < 0 {
					continue
				}
				originalCost := a.Cost
				savedAssign := *a
				ok := a.AddShip(shipID, oris[idx], dess[idx])
				if ok {
					a.GenRoute()
					if a.Cost >= 0 {
						candidates = append(candidates, candidate{ai, a.Cost - originalCost, -1})
					}
				}
				a.RemoveShip(shipID)
				*a = savedAssign
				a.GenRoute()
			} else {
				if dispatch.AssignsLen < MAXASSIGNS {
					tmpAssign := *a
					savedAssign := tmpAssign
					ok := a.AddShip(shipID, oris[idx], dess[idx])
					if ok {
						a.GenRoute()
						if a.Cost >= 0 {
							newCost := a.Cost
							if newCost < 0 {
								newCost = 0
							}
							marg := newCost*penaltyFactor + regretThreshold
							candidates = append(candidates, candidate{ai, marg, -2})
						}
					}
					a.RemoveShip(shipID)
					*a = savedAssign
				}
			}
		}
		bestCandidate := -1
		bestMarginal := 1e100
		for i, c := range candidates {
			score := c.marginal
			if score < bestMarginal {
				bestMarginal = score
				bestCandidate = i
			}
		}
		inserted := false
		if bestCandidate != -1 {
			c := candidates[bestCandidate]
			target := &dispatch.Assigns[c.assignIdx]
			added := target.AddShip(shipID, oris[idx], dess[idx])
			if added {
				target.GenRoute()
				if target.Cost >= 0 {
					inserted = true
					if c.assignIdx == dispatch.AssignsLen {
						dispatch.AssignsLen++
					}
				} else {
					target.RemoveShip(shipID)
					target.GenRoute()
				}
			}
		}
		if !inserted {
			if dispatch.AssignsLen < MAXASSIGNS {
				na := &dispatch.Assigns[dispatch.AssignsLen]
				added := na.AddShip(shipID, oris[idx], dess[idx])
				if added {
					na.GenRoute()
					if na.Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						na.RemoveShip(shipID)
						na.GenRoute()
					}
				}
			}
		}
		if !inserted {
			fallbackAdded := false
			for ai := 0; ai < dispatch.AssignsLen && !fallbackAdded; ai++ {
				fa := &dispatch.Assigns[ai]
				savedFa := *fa
				if fa.AddShip(shipID, oris[idx], dess[idx]) {
					fa.GenRoute()
					if fa.Cost >= 0 {
						fallbackAdded = true
					} else {
						*fa = savedFa
						fa.GenRoute()
					}
				}
			}
			if !fallbackAdded && dispatch.AssignsLen < MAXASSIGNS {
				fa := &dispatch.Assigns[dispatch.AssignsLen]
				if fa.AddShip(shipID, oris[idx], dess[idx]) {
					fa.GenRoute()
					if fa.Cost >= 0 {
						dispatch.AssignsLen++
						fallbackAdded = true
					} else {
						fa.RemoveShip(shipID)
						fa.GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

